    // word because each write operation emits an extra SLOAD to first read the
    // slot's contents, replace the bits taken up by the boolean, and then write
    // back. This is the compiler's defense against contract upgrades and
    // pointer aliasing, and it cannot be disabled.

    // The values being non-zero value makes deployment a bit more expensive,
    // but in exchange the refund on every call to nonReentrant will be lower in
    // amount. Since refunds are capped to a percentage of the total
    // transaction's gas, it is best to keep them low in cases like this one, to
    // increase the likelihood of the full refund coming into effect.
    uint256 private constant NOT_ENTERED = 1;
    uint256 private constant ENTERED = 2;

    uint256 private _status;

    /**
     * @dev Unauthorized reentrant call.
     */
    error ReentrancyGuardReentrantCall();

    constructor() {
        _status = NOT_ENTERED;
    }

    /**
     * @dev Prevents a contract from calling itself, directly or indirectly.
     * Calling a `nonReentrant` function from another `nonReentrant`
     * function is not supported. It is possible to prevent this from happening
     * by making the `nonReentrant` function external, and making it call a
     * `private` function that does the actual work.
     */
    modifier nonReentrant() {
        _nonReentrantBefore();
        _;
        _nonReentrantAfter();
    }

    function _nonReentrantBefore() private {
        // On the first call to nonReentrant, _status will be NOT_ENTERED
        if (_status == ENTERED) {
            revert ReentrancyGuardReentrantCall();
        }

        // Any calls to nonReentrant after this point will fail
        _status = ENTERED;
    }

    function _nonReentrantAfter() private {
        // By storing the original value once again, a refund is triggered (see
        // https://eips.ethereum.org/EIPS/eip-2200)
        _status = NOT_ENTERED;
    }

    /**
     * @dev Returns true if the reentrancy guard is currently set to "entered", which indicates there is a
     * `nonReentrant` function in the call stack.
     */
    function _reentrancyGuardEntered() internal view returns (bool) {
        return _status == ENTERED;
    }
}

// File: newtoken.sol

// Compatible with OpenZeppelin Contracts ^5.5.0
pragma solidity ^0.8.27;

contract VianBirdFarm is ERC20, ERC20Burnable, Ownable, ReentrancyGuard {
    uint256 private constant MAX_SUPPLY = 1_000_000_000 * 1e18;
    uint256 private constant VIAN_BIRD_FARM = (MAX_SUPPLY * 20) / 100; // 20%
    uint256 private constant LIQUIDITY_DEX = (MAX_SUPPLY * 20) / 100; // 20%
    uint256 private constant MARKETING = (MAX_SUPPLY * 10) / 100; // 10%
    uint256 private constant TEAM = (MAX_SUPPLY * 10) / 100; // 10%
    uint256 private constant ECOSYSTEM_GROWTH = (MAX_SUPPLY * 20) / 100; // 20%
    uint256 private constant RESERVE_FUND = (MAX_SUPPLY * 20) / 100; // 20%

    uint256 public constant TEAM_LOCK_PERIOD = 365 days; // 12 months

    uint256 public teamLockStart;
    bool public teamFundsClaimed;

    event TokensAllocated(address indexed to, uint256 amount, string purpose);
    event TeamTokensUnlocked(address indexed teamWallet, uint256 amount);
    event TokenRescued(
        address indexed token,
        address indexed to,
        uint256 amount
    );
    event EtherReceived(address indexed from, uint256 amount);

    constructor(address _owner) ERC20("Vian Bird Farm", "VIAN") Ownable(_owner) {
        _mint(_owner, VIAN_BIRD_FARM);
        emit TokensAllocated(
            _owner,
            VIAN_BIRD_FARM,
            "Vian Bird Farm"
        );

        _mint(_owner, LIQUIDITY_DEX);
        emit TokensAllocated(_owner, LIQUIDITY_DEX, "Liquidity DEX");

        _mint(_owner, MARKETING);
        emit TokensAllocated(_owner, MARKETING, "Marketing");

        _mint(_owner, ECOSYSTEM_GROWTH);
        emit TokensAllocated(_owner, ECOSYSTEM_GROWTH, "Ecosystem Growth");

        _mint(_owner, RESERVE_FUND);
        emit TokensAllocated(_owner, RESERVE_FUND, "Reserve Fund");

        _mint(address(this), TEAM);
        emit TokensAllocated(address(this), TEAM, "Team");

        // Set team lock start time
        teamLockStart = block.timestamp;
        teamFundsClaimed = false;
    }

    // Check if team tokens are unlocked
    function isTeamTokensUnlocked() public view returns (bool) {
        return block.timestamp >= teamLockStart + TEAM_LOCK_PERIOD;
    }

    function getTokenInfo()
        public
        pure
        returns (
            uint256 MAX_SUPPLY_,
            uint256 VIAN_BIRD_FARM_,
            uint256 LIQUIDITY_DEX_,
            uint256 MARKETING_,
            uint256 TEAM_,
            uint256 ECOSYSTEM_GROWTH_,
            uint256 RESERVE_FUND_
        )
    {
        return (
            MAX_SUPPLY,
            VIAN_BIRD_FARM,
            LIQUIDITY_DEX,
            MARKETING,
            TEAM,
            ECOSYSTEM_GROWTH,
            RESERVE_FUND
        );
    }

    /// @notice Claim team funds after lock period. Only owner and only once.
    function claimTeamFunds(
        address teamWallet
    ) external nonReentrant onlyOwner {
        require(teamWallet != address(0), "Invalid team wallet");
        require(isTeamTokensUnlocked(), "Lock period not completed");
        require(!teamFundsClaimed, "Already claimed");

        uint256 lockedAmount = balanceOf(address(this));
        require(lockedAmount >= TEAM, "Insufficient locked tokens in contract");

        teamFundsClaimed = true;
        _transfer(address(this), teamWallet, TEAM);
        emit TeamTokensUnlocked(teamWallet, TEAM);
    }

    // ------------------------------------------------------------------------
    // Fallback & Receive - Handle accidental ETH or ERC20 transfers
    // ------------------------------------------------------------------------

    /// @notice Called when ETH is sent with empty calldata
    receive() external payable {
        emit EtherReceived(msg.sender, msg.value);
        revert("Direct ETH transfers not accepted");
    }

    /// @notice Called when ETH is sent with data or unknown function call
    fallback() external payable {
        emit EtherReceived(msg.sender, msg.value);
        revert("Invalid call or ETH transfer");
    }

    function withdrawETH(
        address payable to,
        uint256 amount
    ) external payable onlyOwner nonReentrant {
        require(to != address(0), "Invalid recipient");
        require(
            amount > 0 && amount <= address(this).balance,
            "Invalid amount"
        );
        (bool success, ) = to.call{value: amount}("");
        require(success, "ETH transfer failed");
    }

    function withdrawToken(
        address token,
        address to,
        uint256 amount
    ) external onlyOwner nonReentrant {
        require(isTeamTokensUnlocked(), "Lock period not completed");
        require(to != address(0), "Invalid recipient");
        require(amount > 0, "Amount must be greater than zero");

        IERC20 t = IERC20(token);
        uint256 balance = t.balanceOf(address(this));
        require(balance >= amount, "Not enough token balance");

        t.transfer(to, amount);
        emit TokenRescued(token, to, amount);
    }
}
